import{_ as e,o as a,c as i,ag as t}from"./chunks/framework.Culc7SYV.js";const c=JSON.parse('{"title":"Burying Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Burying-Cards.md","filePath":"Burying-Cards.md","lastUpdated":1772690052000}'),s={name:"Burying-Cards.md"};function o(n,r,d,u,l,p){return a(),i("div",null,[...r[0]||(r[0]=[t('<h1 id="burying-cards" tabindex="-1">Burying Cards <a class="header-anchor" href="#burying-cards" aria-label="Permalink to &quot;Burying Cards&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Burying removes a card from today’s session and brings it back tomorrow. It does <strong>not</strong> reset or change scheduling values (interval, stability, difficulty).</p><h2 id="bury-steps" tabindex="-1">Bury Steps <a class="header-anchor" href="#bury-steps" aria-label="Permalink to &quot;Bury Steps&quot;">​</a></h2><p>During review:</p><ul><li>press <code>B</code>, or</li><li>open the More menu and choose <strong>Bury</strong>.</li></ul><p>If you skip the same card three times in one session, LearnKit offers a <strong>Bury for today?</strong> prompt.</p><h2 id="return-rule" tabindex="-1">Return Rule <a class="header-anchor" href="#return-rule" aria-label="Permalink to &quot;Return Rule&quot;">​</a></h2><p>Buried cards are automatically unburied at local midnight.</p><h2 id="find-buried" tabindex="-1">Find Buried <a class="header-anchor" href="#find-buried" aria-label="Permalink to &quot;Find Buried&quot;">​</a></h2><p>Open <a href="./Card-Browser">Card Browser</a> and filter Stage = Buried.</p><h2 id="limits" tabindex="-1">Limits <a class="header-anchor" href="#limits" aria-label="Permalink to &quot;Limits&quot;">​</a></h2><ul><li>Burying is temporary (today only).</li><li>Burying does not delete cards.</li><li>For long-term removal from review, use <a href="./Suspending-Cards">Suspending Cards</a>.</li></ul>',14)])])}const m=e(s,[["render",o]]);export{c as __pageData,m as default};
